import React, { useState } from 'react';
import { toast } from 'react-toastify';
import moment from 'moment';
import { scheduleAPI } from '../services/api';

const GenerateSchedule = () => {
  const [startDate, setStartDate] = useState(moment().format('YYYY-MM-DD'));
  const [excludeDateInput, setExcludeDateInput] = useState('');
  const [excludeDates, setExcludeDates] = useState([]);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);

  const addExcludeDate = () => {
    if (!excludeDateInput) {
      return;
    }
    if (excludeDates.includes(excludeDateInput)) {
      toast.warning('Date already added');
      return;
    }
    setExcludeDates((prev) => [...prev, excludeDateInput].sort());
    setExcludeDateInput('');
  };

  const removeExcludeDate = (dateToRemove) => {
    setExcludeDates((prev) => prev.filter((date) => date !== dateToRemove));
  };

  const handleGenerate = async () => {
    try {
      setLoading(true);
      const response = await scheduleAPI.generate({
        startDate,
        excludeDates,
      });
      setResult(response.data);
      toast.success('Schedule generated successfully');
    } catch (error) {
      toast.error(error.response?.data?.error || 'Failed to generate schedule');
    } finally {
      setLoading(false);
    }
  };

  const handleClearSchedule = async () => {
    try {
      await scheduleAPI.clear();
      setResult(null);
      toast.success('Schedule cleared successfully');
    } catch (error) {
      toast.error('Failed to clear schedule');
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-lg shadow-md p-6">
        <h1 className="text-3xl font-bold text-gray-800 mb-2">Generate Schedule</h1>
        <p className="text-gray-600">Create exam timetable using the CSP scheduler.</p>
      </div>

      <div className="bg-white rounded-lg shadow-md p-6 space-y-6">
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-2">
            Start Date
          </label>
          <input
            type="date"
            className="input-field max-w-xs"
            value={startDate}
            onChange={(event) => setStartDate(event.target.value)}
          />
        </div>

        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-2">
            Exclude Dates
          </label>
          <div className="flex flex-wrap gap-2 items-center">
            <input
              type="date"
              className="input-field max-w-xs"
              value={excludeDateInput}
              onChange={(event) => setExcludeDateInput(event.target.value)}
            />
            <button type="button" className="btn-secondary" onClick={addExcludeDate}>
              Add Date
            </button>
          </div>
          {excludeDates.length > 0 && (
            <div className="mt-3 flex flex-wrap gap-2">
              {excludeDates.map((date) => (
                <button
                  key={date}
                  type="button"
                  onClick={() => removeExcludeDate(date)}
                  className="px-3 py-1 bg-red-100 text-red-700 rounded-full text-sm"
                >
                  {date} x
                </button>
              ))}
            </div>
          )}
        </div>

        <div className="flex flex-wrap gap-3">
          <button
            type="button"
            onClick={handleGenerate}
            className="btn-primary"
            disabled={loading}
          >
            {loading ? 'Generating...' : 'Generate Timetable'}
          </button>
          <button
            type="button"
            onClick={handleClearSchedule}
            className="btn-danger"
            disabled={loading}
          >
            Clear Saved Schedule
          </button>
        </div>
      </div>

      {result && (
        <div className="bg-white rounded-lg shadow-md p-6 space-y-4">
          <h2 className="text-2xl font-semibold text-gray-800">Generation Result</h2>
          {result.stats && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="bg-blue-50 rounded-lg p-4">
                <p className="text-sm text-gray-600">Total Exams</p>
                <p className="text-2xl font-bold text-blue-600">{result.stats.total_exams || 0}</p>
              </div>
              <div className="bg-green-50 rounded-lg p-4">
                <p className="text-sm text-gray-600">Total Days</p>
                <p className="text-2xl font-bold text-green-600">{result.stats.total_days || 0}</p>
              </div>
              <div className="bg-yellow-50 rounded-lg p-4">
                <p className="text-sm text-gray-600">Departments</p>
                <p className="text-2xl font-bold text-yellow-600">{result.stats.total_departments || 0}</p>
              </div>
            </div>
          )}

          <div>
            <h3 className="text-lg font-semibold text-gray-800 mb-2">Preview</h3>
            {result.timetable?.length ? (
              <div className="overflow-x-auto">
                <table className="min-w-full">
                  <thead>
                    <tr className="table-header">
                      <th className="px-4 py-3 text-left">Date</th>
                      <th className="px-4 py-3 text-left">Slot</th>
                      <th className="px-4 py-3 text-left">Subject</th>
                      <th className="px-4 py-3 text-left">Hall</th>
                      <th className="px-4 py-3 text-left">Students</th>
                    </tr>
                  </thead>
                  <tbody>
                    {result.timetable.slice(0, 10).map((exam, index) => (
                      <tr key={`${exam.subject_code}-${index}`} className="table-row">
                        <td className="px-4 py-3">{exam.date}</td>
                        <td className="px-4 py-3">{exam.slot}</td>
                        <td className="px-4 py-3">
                          <p className="font-semibold">{exam.subject_code}</p>
                          <p className="text-sm text-gray-500">{exam.subject_name}</p>
                        </td>
                        <td className="px-4 py-3">{exam.hall}</td>
                        <td className="px-4 py-3">{exam.students_count}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            ) : (
              <p className="text-gray-500">No exams generated.</p>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default GenerateSchedule;
